{% assign nutrition = product.metafields.custom.nutrition.value %}

{% if nutrition and nutrition.rows %}
  <div class="nutrition-accordion">
    <details class="nutrition-accordion__details" open>
      <summary class="nutrition-accordion__summary">
        {{ nutrition.title | default: 'Nutritivne vrednosti' }}
      </summary>

      <div class="nutrition-accordion__content">
        <table class="nutrition-accordion__table">
          <thead>
            <tr>
              <th>Stavka</th>
              <th>Iznos</th>
            </tr>
          </thead>

          <tbody>
            {% for row in nutrition.rows %}
              <tr class="{% if row.is_subrow %}is-subrow{% endif %}">
                <td>
                  {% if row.is_subrow %}
                    — {{ row.label }}
                  {% else %}
                    {{ row.label }}
                  {% endif %}
                </td>
                <td>{{ row.value }}</td>
              </tr>
            {% endfor %}
          </tbody>
        </table>
      </div>
    </details>
  </div>
{% endif %}
<style>
.nutrition-accordion__details {
  border: 1px solid rgba(0,0,0,0.12);
  border-radius: 10px;
  padding: 12px 14px;
}

.nutrition-accordion__summary {
  cursor: default; /* da izgleda kao accordion header ali bez "click" osećaja */
  list-style: none;
  font-weight: 600;
}

.nutrition-accordion__summary::-webkit-details-marker { display: none; }

.nutrition-accordion__content {
  margin-top: 12px;
}

.nutrition-accordion__table {
  width: 100%;
  border-collapse: collapse;
}

.nutrition-accordion__table th,
.nutrition-accordion__table td {
  padding: 10px 0;
  border-bottom: 1px solid rgba(0,0,0,0.10);
  vertical-align: top;
}

.nutrition-accordion__table th:last-child,
.nutrition-accordion__table td:last-child {
  text-align: right;
  white-space: nowrap;
}

.nutrition-accordion__table tr.is-subrow td:first-child {
  padding-left: 18px;
  opacity: 0.85;
}
</style>
<script>
  document.addEventListener('click', function (e) {
    const summary = e.target.closest('.nutrition-accordion__summary');
    if (!summary) return;
    e.preventDefault(); // spreči toggle
  });
</script>
